#include<bits/stdc++.h>
using namespace std;
long long a[100005],n,dp[100005];
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    dp[0]=0;
    dp[1]=0;
    dp[2]=a[1]+a[2];
    for(int i=3;i<=n;i++){
        dp[i]=max(dp[i-1],dp[i-3]+a[i]+a[i-1]);
    }
    cout<<dp[n];
    return 0;
}
